#ifndef TOP_P_SAMPLING_V128256_KERNEL_H_
#define TOP_P_SAMPLING_V128256_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>

static constexpr int kVocabSize = 128256;

void top_p_sampling_from_probs_v128256_launcher(
    const float* probs,   // [B, 128256]
    const float* top_p,   // [B]
    int64_t* samples,     // [B]
    int batch_size,
    uint64_t rng_seed,
    cudaStream_t stream);

#endif  // TOP_P_SAMPLING_V128256_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>
#include <math_constants.h>

#if defined(__CUDA_ARCH__)
#define LDG(ptr) __ldg(ptr)
#else
#define LDG(ptr) (*(ptr))
#endif

// -----------------------------
// RNG: splitmix64 (deterministic per-row)
// -----------------------------
__device__ __forceinline__ uint64_t splitmix64_stateless(uint64_t x) {
  x += 0x9e3779b97f4a7c15ull;
  x = (x ^ (x >> 30)) * 0xbf58476d1ce4e5b9ull;
  x = (x ^ (x >> 27)) * 0x94d049bb133111ebull;
  return x ^ (x >> 31);
}

__device__ __forceinline__ float u01_from_u64(uint64_t x) {
  // 24-bit mantissa uniform in [0,1)
  const uint32_t mant = (uint32_t)(x >> 40);
  return (float)mant * (1.0f / 16777216.0f);
}

// -----------------------------
// Reductions
// -----------------------------
__device__ __forceinline__ float warp_reduce_sum(float v) {
#pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(0xffffffff, v, offset);
  }
  return v;
}

template <int BLOCK>
__device__ __forceinline__ float block_reduce_sum(float v) {
  static_assert(BLOCK % 32 == 0, "BLOCK must be warp-multiple");
  __shared__ float smem[BLOCK / 32];
  const int lane = threadIdx.x & 31;
  const int warp = threadIdx.x >> 5;
  v = warp_reduce_sum(v);
  if (lane == 0) smem[warp] = v;
  __syncthreads();
  v = (threadIdx.x < (BLOCK / 32)) ? smem[lane] : 0.0f;
  if (warp == 0) v = warp_reduce_sum(v);
  return v;
}

struct KV {
  float v;
  int i;
};

__device__ __forceinline__ KV kv_max(KV a, KV b) {
  if (b.v > a.v) return b;
  if (b.v < a.v) return a;
  return (b.i < a.i) ? b : a;
}

template <int BLOCK>
__device__ __forceinline__ KV block_reduce_argmax(KV best) {
  static_assert(BLOCK % 32 == 0, "BLOCK must be warp-multiple");
  __shared__ float svals[BLOCK / 32];
  __shared__ int sidx[BLOCK / 32];

  const int lane = threadIdx.x & 31;
  const int warp = threadIdx.x >> 5;

  float v = best.v;
  int idx = best.i;

#pragma unroll
  for (int off = 16; off > 0; off >>= 1) {
    float v2 = __shfl_down_sync(0xffffffff, v, off);
    int i2 = __shfl_down_sync(0xffffffff, idx, off);
    if (v2 > v || (v2 == v && i2 < idx)) {
      v = v2;
      idx = i2;
    }
  }

  if (lane == 0) {
    svals[warp] = v;
    sidx[warp] = idx;
  }
  __syncthreads();

  if (warp == 0) {
    float bv = (threadIdx.x < (BLOCK / 32)) ? svals[lane] : -CUDART_INF_F;
    int bi = (threadIdx.x < (BLOCK / 32)) ? sidx[lane] : 0;

#pragma unroll
    for (int off = 16; off > 0; off >>= 1) {
      float v2 = __shfl_down_sync(0xffffffff, bv, off);
      int i2 = __shfl_down_sync(0xffffffff, bi, off);
      if (v2 > bv || (v2 == bv && i2 < bi)) {
        bv = v2;
        bi = i2;
      }
    }
    if (lane == 0) {
      svals[0] = bv;
      sidx[0] = bi;
    }
  }
  __syncthreads();
  return KV{svals[0], sidx[0]};
}

// -----------------------------
// Correct multinomial sampling in ORIGINAL index order (matches reference)
// Two-pass: sum then scan for threshold crossing.
// Fix: choose first TRUE across entire block-chunk, not per-warp ballot.
// -----------------------------
template <int BLOCK>
__device__ __forceinline__ int sample_multinomial_ordered(const float* __restrict__ rowp, float u01) {
  float partial = 0.0f;
  for (int j = threadIdx.x; j < kVocabSize; j += BLOCK) partial += LDG(rowp + j);
  float total = block_reduce_sum<BLOCK>(partial);

  __shared__ float total_s;
  if (threadIdx.x == 0) total_s = total;
  __syncthreads();

  if (!(total_s > 0.0f) || !isfinite(total_s)) {
    KV best{-CUDART_INF_F, 0};
    for (int j = threadIdx.x; j < kVocabSize; j += BLOCK) best = kv_max(best, KV{LDG(rowp + j), j});
    KV out = block_reduce_argmax<BLOCK>(best);
    return out.i;
  }

  const float thr = u01 * total_s;

  __shared__ float scan_s[BLOCK];
  float cdf_base = 0.0f;

  for (int base = 0; base < kVocabSize; base += BLOCK) {
    const int j = base + threadIdx.x;
    const float vj = (j < kVocabSize) ? LDG(rowp + j) : 0.0f;

    scan_s[threadIdx.x] = vj;
    __syncthreads();

    // inclusive scan in shared memory (BLOCK=256)
#pragma unroll
    for (int offset = 1; offset < BLOCK; offset <<= 1) {
      float t = (threadIdx.x >= offset) ? scan_s[threadIdx.x - offset] : 0.0f;
      __syncthreads();
      scan_s[threadIdx.x] += t;
      __syncthreads();
    }

    const float my_cdf = cdf_base + scan_s[threadIdx.x];
    const bool pred = (j < kVocabSize) && (my_cdf >= thr);

    // Compute earliest index in this chunk where pred is true (across entire block)
    unsigned m = __ballot_sync(0xffffffff, pred);
    int found = -1;

    // each warp checks its own ballot; warp id 0..7
    if (m) {
      const int first_lane = __ffs(m) - 1;
      found = (threadIdx.x & ~31) + first_lane;  // offset within chunk [0,BLOCK)
    }

    // Reduce minimum found across block
    int local = (found >= 0) ? found : 1e9;
    // warp reduce min
#pragma unroll
    for (int off = 16; off > 0; off >>= 1) {
      int other = __shfl_down_sync(0xffffffff, local, off);
      local = min(local, other);
    }

    __shared__ int warp_min[BLOCK / 32];
    const int lane = threadIdx.x & 31;
    const int warp = threadIdx.x >> 5;
    if (lane == 0) warp_min[warp] = local;
    __syncthreads();

    int block_min = 1e9;
    if (warp == 0) {
      int v = (threadIdx.x < (BLOCK / 32)) ? warp_min[lane] : 1e9;
#pragma unroll
      for (int off = 16; off > 0; off >>= 1) {
        int other = __shfl_down_sync(0xffffffff, v, off);
        v = min(v, other);
      }
      if (lane == 0) warp_min[0] = v;
    }
    __syncthreads();
    block_min = warp_min[0];

    if (block_min < 1e9) return base + block_min;

    cdf_base += scan_s[BLOCK - 1];
    __syncthreads();
  }

  return kVocabSize - 1;
}

// -----------------------------
// top-p sampling kernel (correctness-first, deterministic, no huge temp)
// Implements true top-p set selection by finding threshold via binary search on prob value,
// then samples from filtered distribution in ORIGINAL order (matches reference multinomial call).
// Remaining mismatch vs reference: reference includes all tokens above a prob cutoff induced by sort;
// our cutoff-by-prob matches that set except for ties around boundary; acceptable for softmax outputs.
// -----------------------------
template <int BLOCK>
__global__ void top_p_sampling_from_probs_v128256_kernel(
    const float* __restrict__ probs,
    const float* __restrict__ top_p,
    int64_t* __restrict__ samples,
    int batch_size,
    uint64_t seed) {
  const int row = (int)blockIdx.x;
  if (row >= batch_size) return;

  const float* rowp = probs + (size_t)row * (size_t)kVocabSize;
  const float p = LDG(top_p + row);

  const uint64_t r0 =
      splitmix64_stateless(seed ^ (0xD1B54A32D192ED03ull + (uint64_t)row * 0x9E3779B97F4A7C15ull));
  const float u = u01_from_u64(r0);

  // p <= 0 => argmax
  if (!(p > 0.0f)) {
    KV best{-CUDART_INF_F, 0};
    for (int j = threadIdx.x; j < kVocabSize; j += BLOCK) best = kv_max(best, KV{LDG(rowp + j), j});
    KV out = block_reduce_argmax<BLOCK>(best);
    if (threadIdx.x == 0) samples[row] = (int64_t)out.i;
    return;
  }

  // p >= 1 => full multinomial in original order
  if (p >= 1.0f) {
    const int chosen = sample_multinomial_ordered<BLOCK>(rowp, u);
    if (threadIdx.x == 0) samples[row] = (int64_t)chosen;
    return;
  }

  // Find max prob for search range
  KV best{-CUDART_INF_F, 0};
  for (int j = threadIdx.x; j < kVocabSize; j += BLOCK) best = kv_max(best, KV{LDG(rowp + j), j});
  KV mx = block_reduce_argmax<BLOCK>(best);

  __shared__ float maxp_s;
  if (threadIdx.x == 0) maxp_s = mx.v;
  __syncthreads();

  float hi = maxp_s;
  if (!(hi > 0.0f) || !isfinite(hi)) {
    const int chosen = sample_multinomial_ordered<BLOCK>(rowp, u);
    if (threadIdx.x == 0) samples[row] = (int64_t)chosen;
    return;
  }

  float lo = 0.0f;

  // Binary search threshold t: sum_{v>=t} prob >= p, and as large t as possible.
#pragma unroll 1
  for (int it = 0; it < 20; ++it) {
    const float mid = 0.5f * (lo + hi);
    float psum = 0.0f;
    for (int j = threadIdx.x; j < kVocabSize; j += BLOCK) {
      const float v = LDG(rowp + j);
      if (v >= mid) psum += v;
    }
    psum = block_reduce_sum<BLOCK>(psum);

    __shared__ float psum_s;
    if (threadIdx.x == 0) psum_s = psum;
    __syncthreads();

    if (psum_s >= p)
      lo = mid;
    else
      hi = mid;
    __syncthreads();
  }

  const float thr_prob = lo;

  // Compute kept_sum
  float kept_sum = 0.0f;
  for (int j = threadIdx.x; j < kVocabSize; j += BLOCK) {
    const float v = LDG(rowp + j);
    if (v >= thr_prob) kept_sum += v;
  }
  kept_sum = block_reduce_sum<BLOCK>(kept_sum);

  __shared__ float kept_sum_s;
  if (threadIdx.x == 0) kept_sum_s = kept_sum;
  __syncthreads();

  if (!(kept_sum_s > 0.0f) || !isfinite(kept_sum_s)) {
    const int chosen = sample_multinomial_ordered<BLOCK>(rowp, u);
    if (threadIdx.x == 0) samples[row] = (int64_t)chosen;
    return;
  }

  // Sample from filtered distribution in original order:
  const float thr = u * kept_sum_s;

  __shared__ float scan_s[BLOCK];
  float cdf_base = 0.0f;

  for (int base = 0; base < kVocabSize; base += BLOCK) {
    const int j = base + threadIdx.x;

    float vj = 0.0f;
    if (j < kVocabSize) {
      const float v = LDG(rowp + j);
      vj = (v >= thr_prob) ? v : 0.0f;
    }

    scan_s[threadIdx.x] = vj;
    __syncthreads();

#pragma unroll
    for (int offset = 1; offset < BLOCK; offset <<= 1) {
      float t = (threadIdx.x >= offset) ? scan_s[threadIdx.x - offset] : 0.0f;
      __syncthreads();
      scan_s[threadIdx.x] += t;
      __syncthreads();
    }

    const float my_cdf = cdf_base + scan_s[threadIdx.x];
    const bool pred = (j < kVocabSize) && (vj > 0.0f) && (my_cdf >= thr);

    unsigned m = __ballot_sync(0xffffffff, pred);
    int found = -1;
    if (m) {
      const int first_lane = __ffs(m) - 1;
      found = (threadIdx.x & ~31) + first_lane;
    }

    int local = (found >= 0) ? found : 1e9;
#pragma unroll
    for (int off = 16; off > 0; off >>= 1) {
      int other = __shfl_down_sync(0xffffffff, local, off);
      local = min(local, other);
    }

    __shared__ int warp_min[BLOCK / 32];
    const int lane = threadIdx.x & 31;
    const int warp = threadIdx.x >> 5;
    if (lane == 0) warp_min[warp] = local;
    __syncthreads();

    if (warp == 0) {
      int v = (threadIdx.x < (BLOCK / 32)) ? warp_min[lane] : 1e9;
#pragma unroll
      for (int off = 16; off > 0; off >>= 1) {
        int other = __shfl_down_sync(0xffffffff, v, off);
        v = min(v, other);
      }
      if (lane == 0) warp_min[0] = v;
    }
    __syncthreads();

    const int block_min = warp_min[0];
    if (block_min < 1e9) {
      if (threadIdx.x == 0) samples[row] = (int64_t)(base + block_min);
      return;
    }

    cdf_base += scan_s[BLOCK - 1];
    __syncthreads();
  }

  if (threadIdx.x == 0) samples[row] = (int64_t)(kVocabSize - 1);
}

void top_p_sampling_from_probs_v128256_launcher(
    const float* probs,
    const float* top_p,
    int64_t* samples,
    int batch_size,
    uint64_t rng_seed,
    cudaStream_t stream) {
  constexpr int BLOCK = 256;
  dim3 grid((unsigned)batch_size, 1, 1);
  dim3 block(BLOCK, 1, 1);
  top_p_sampling_from_probs_v128256_kernel<BLOCK><<<grid, block, 0, stream>>>(
      probs, top_p, samples, batch_size, rng_seed);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDAGuard.h>

#include <chrono>
#include <cstdint>
#include <stdexcept>
#include <string>

#include "kernel.h"

static inline void check_cuda_contig(const torch::Tensor& t, const char* name) {
  if (!t.defined()) throw std::runtime_error(std::string(name) + " is undefined");
  if (!t.device().is_cuda()) throw std::runtime_error(std::string(name) + " must be a CUDA tensor");
  if (!t.is_contiguous()) throw std::runtime_error(std::string(name) + " must be contiguous");
}

static inline void check_dtype(const torch::Tensor& t, c10::ScalarType dt, const char* name) {
  if (t.scalar_type() != dt) {
    throw std::runtime_error(std::string(name) + " must have dtype " + std::string(c10::toString(dt)));
  }
}

static inline torch::Tensor run_impl(const torch::Tensor& probs, const torch::Tensor& top_p) {
  check_cuda_contig(probs, "probs");
  check_cuda_contig(top_p, "top_p");
  check_dtype(probs, torch::kFloat32, "probs");
  check_dtype(top_p, torch::kFloat32, "top_p");

  if (probs.dim() != 2) throw std::runtime_error("probs must have shape [batch_size, vocab_size]");
  if (top_p.dim() != 1) throw std::runtime_error("top_p must have shape [batch_size]");

  const int64_t batch_size = probs.size(0);
  const int64_t vocab_size = probs.size(1);
  if (vocab_size != kVocabSize) throw std::runtime_error("vocab_size must be exactly 128256");
  if (top_p.size(0) != batch_size) throw std::runtime_error("top_p size must match batch_size");
  if (top_p.device() != probs.device()) throw std::runtime_error("probs and top_p must be on same CUDA device");

  c10::cuda::CUDAGuard device_guard(probs.device());

  auto out = torch::empty({batch_size},
                          torch::TensorOptions().dtype(torch::kInt64).device(probs.device()));

  const float* probs_ptr = probs.data_ptr<float>();
  const float* top_p_ptr = top_p.data_ptr<float>();
  int64_t* out_ptr = out.data_ptr<int64_t>();

  cudaStream_t stream = at::cuda::getDefaultCUDAStream(probs.device().index());

  uint64_t seed =
      (uint64_t)std::chrono::high_resolution_clock::now().time_since_epoch().count();
  seed ^= (uint64_t)(uintptr_t)probs_ptr * 0x9E3779B97F4A7C15ull;
  seed ^= (uint64_t)(uintptr_t)top_p_ptr * 0xD1B54A32D192ED03ull;

  top_p_sampling_from_probs_v128256_launcher(
      probs_ptr, top_p_ptr, out_ptr, (int)batch_size, seed, stream);

  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    throw std::runtime_error(std::string("CUDA kernel launch failed: ") + cudaGetErrorString(err));
  }
  err = cudaStreamSynchronize(stream);
  if (err != cudaSuccess) {
    throw std::runtime_error(std::string("CUDA stream sync failed: ") + cudaGetErrorString(err));
  }

  return out;
}

torch::Tensor run(torch::Tensor probs, torch::Tensor top_p) {
  return run_impl(probs, top_p);
}

torch::Tensor run_kwargs(const torch::Tensor& probs, const torch::Tensor& top_p) {
  return run_impl(probs, top_p);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "top_p_sampling_from_probs_v128256 (CUDA)");
  m.def("run_kwargs", &run_kwargs, "top_p_sampling_from_probs_v128256 (CUDA, kwargs-friendly)");
}
